async (params, browser) => {
  // Open notifications
  await browser.open('https://x.com/notifications')

  // Wait for page content
  await browser.waitForSelector('[data-testid=\'cellInnerDiv\']', 15000)

  // Let page settle
  await browser.wait(1000)

  // Load more notifications
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract notifications
  const notifications = await browser.evaluate(`const notifications = []; const cells = document.querySelectorAll('article[data-testid="tweet"], [data-testid="notification"], [data-testid="cellInnerDiv"]'); let count = 0; cells.forEach(cell => { if (count >= 15) return; const text = cell.textContent.trim(); if (text.length < 5) return; const timeEl = cell.querySelector('time'); const linkEls = cell.querySelectorAll('a[href*="/status/"]'); const userLinks = cell.querySelectorAll('a[role="link"][href^="/"]'); let type = 'unknown'; if (text.match(/liked/i)) type = 'like'; else if (text.match(/retweeted/i)) type = 'retweet'; else if (text.match(/followed/i)) type = 'follow'; else if (text.match(/replied/i) || text.match(/replying to/i)) type = 'reply'; else if (text.match(/mentioned/i)) type = 'mention'; const shortText = text.substring(0, 200); notifications.push({ type: type, text: shortText, time: timeEl ? timeEl.getAttribute('datetime') : '', tweet_url: linkEls.length > 0 ? 'https://x.com' + linkEls[0].getAttribute('href') : '' }); count++; }); return { count: notifications.length, notifications: notifications }`)

  return notifications
}
